scwin.lc_gbun_onchange = async function(e) {
    if (scwin.actionFlag == "CREATE") {
        if (ed_mrn.getValue().length < 1) {
            await $c.win.alert('MRN No를 입력해 주십시오.');
            ed_mrn.setFocus();
            lc_gbun.setSelectedIndex(-1);
            return;
        }
        if (ed_hblno.getValue().length < 1) {
            await $c.win.alert('House b/l No를 입력해 주십시오.');
            ed_hblno.setFocus();
            lc_gbun.setSelectedIndex(-1);
            return;
        }

        if (lc_gbun.getSelectedIndex() == 0) {
            $c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1]);
            scwin.f_Set("CREATEMORE");
        } else {
            $c.gus.cfEnableObjects([tr_tab_center0]);
            $c.gus.cfDisableObjects([tr_tab_center1]);
            scwin.f_ClearData();
        }
    }
};
